// Logs is the resolver for the logs field.
func (r *queryResolver) Logs(ctx context.Context, search *string, limit *int) ([]*model.LogEntry, error) {
	entries := r.LogBuffer.Entries()

	var result []*model.LogEntry
	for i := len(entries) - 1; i >= 0; i-- {
		e := entries[i]
		if search != nil && *search != "" {
			if !containsFold(e.Message, *search) && !attrsContainFold(e.Attrs, *search) {
				continue
			}
		}
		result = append(result, mapLogEntry(e))
		if limit != nil && len(result) >= *limit {
			break
		}
	}

	for i, j := 0, len(result)-1; i < j; i, j = i+1, j-1 {
		result[i], result[j] = result[j], result[i]
	}

	return result, nil
}

// Activity is the resolver for the activity field.
func (r *queryResolver) Activity(ctx context.Context, filter *model.ActivityFilter) ([]*model.ActivityEvent, error) {
	q := store.ActivityQuery{Limit: 500}
	if filter != nil {
		if types, ok := filter.Types.ValueOK(); ok {
			q.Types = types
		}
		if did, ok := filter.DeviceID.ValueOK(); ok && did != nil {
			q.DeviceID = did
		}
		if rid, ok := filter.RoomID.ValueOK(); ok && rid != nil {
			q.RoomID = rid
		}
		if since, ok := filter.Since.ValueOK(); ok && since != nil {
			q.Since = since
		}
		if adv, ok := filter.Advanced.ValueOK(); ok && adv != nil {
			q.Advanced = *adv
		}
		if lim, ok := filter.Limit.ValueOK(); ok && lim != nil && *lim > 0 {
			q.Limit = *lim
		}
		if before, ok := filter.Before.ValueOK(); ok && before != nil && *before != "" {
			n, err := strconv.ParseInt(*before, 10, 64)
			if err != nil {
				return nil, fmt.Errorf("invalid before cursor %q: %w", *before, err)
			}
			q.Before = &n
		}
	}
	rows, err := r.Store.QueryActivityEvents(ctx, q)
	if err != nil {
		return nil, err
	}
	result := make([]*model.ActivityEvent, len(rows))
	for i, row := range rows {
		result[i] = mapActivityEvent(row)
	}
	return result, nil
}

// SetupStatus is the resolver for the setupStatus field. Whitelisted — callable
// without authentication so the frontend can decide whether to show /setup.
func (r *queryResolver) SetupStatus(ctx context.Context) (*model.SetupStatus, error) {
	count, err := r.Store.CountUsers(ctx)
	if err != nil {
		return nil, err
	}
	mqtt, err := r.Store.GetMQTTConfig(ctx)
	if err != nil {
		return nil, err
	}
	return &model.SetupStatus{
		HasInitialUser: count > 0,
		MqttConfigured: mqtt != nil && mqtt.Broker != "",
	}, nil
}

