// LogStream is the resolver for the logStream field.
func (r *subscriptionResolver) LogStream(ctx context.Context) (<-chan *model.LogEntry, error) {
	ch, unsub := r.LogBuffer.Subscribe()
	out := make(chan *model.LogEntry, 1)

	go func() {
		defer close(out)
		defer unsub()

		for {
			select {
			case <-ctx.Done():
				return
			case e, ok := <-ch:
				if !ok {
					return
				}
				select {
				case out <- mapLogEntry(e):
				case <-ctx.Done():
					return
				}
			}
		}
	}()

	return out, nil
}

// ActivityStream is the resolver for the activityStream field.
func (r *subscriptionResolver) ActivityStream(ctx context.Context, advanced *bool) (<-chan *model.ActivityEvent, error) {
	showAdvanced := advanced != nil && *advanced

	ch, unsub := r.ActivityBuffer.Subscribe()
	out := make(chan *model.ActivityEvent, 16)

	go func() {
		defer close(out)
		defer unsub()

		for {
			select {
			case <-ctx.Done():
				return
			case row, ok := <-ch:
				if !ok {
					return
				}
				if !showAdvanced && (row.Type == "command.requested" || row.Type == "automation.node_activated") {
					continue
				}
				select {
				case out <- mapActivityEvent(row):
				case <-ctx.Done():
					return
				}
			}
		}
	}()

	return out, nil
}

// Mutation returns MutationResolver implementation.
func (r *Resolver) Mutation() MutationResolver { return &mutationResolver{r} }

// Query returns QueryResolver implementation.
func (r *Resolver) Query() QueryResolver { return &queryResolver{r} }

// Subscription returns SubscriptionResolver implementation.
func (r *Resolver) Subscription() SubscriptionResolver { return &subscriptionResolver{r} }

type mutationResolver struct{ *Resolver }
type queryResolver struct{ *Resolver }
type subscriptionResolver struct{ *Resolver }
